import unittest

class TestSolution(unittest.TestCase):
    def test_x_wins_top_row(self):
        board = [['X','X','X'], ['O','O','.'], ['.','.','.']]
        self.assertEqual(check_winner(board), 'X')

    def test_o_wins_left_column(self):
        board = [['O','X','.'], ['O','X','.'], ['O','.','.']]
        self.assertEqual(check_winner(board), 'O')

    def test_draw_full_board(self):
        board = [['X','O','X'], ['X','O','O'], ['O','X','X']]
        self.assertEqual(check_winner(board), 'Draw')

    def test_hidden_x_wins_main_diagonal(self):
        board = [['X','O','O'], ['.','X','.'], ['.','.','X']]
        self.assertEqual(check_winner(board), 'X')

    def test_hidden_o_wins_anti_diagonal(self):
        board = [['.','.','O'], ['.','O','.'], ['O','.','.']]
        self.assertEqual(check_winner(board), 'O')

    def test_hidden_o_wins_middle_row(self):
        board = [['X','.','X'], ['O','O','O'], ['X','.','.']]
        self.assertEqual(check_winner(board), 'O')

    def test_hidden_x_wins_right_column(self):
        board = [['.','O','X'], ['.','O','X'], ['O','.','X']]
        self.assertEqual(check_winner(board), 'X')

    def test_hidden_empty_board(self):
        board = [['.','.','.'],['.','.','.'],['.','.','.']] 
        self.assertEqual(check_winner(board), 'Draw')

if __name__ == '__main__':
    unittest.main()
